section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/ai-prompt-as-commit-artifact.json",
  "title": "AI Prompt as Commit Artefact",
  "type": "object",
  "required": [
    "artefact_id",
    "commit_sha",
    "prompt",
    "model",
    "context_refs",
    "verifier",
    "author",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "commit_sha": {
      "type": "string",
      "description": "git short SHA of the commit being annotated",
      "minLength": 1
    },
    "prompt": {
      "type": "string",
      "description": "verbatim prompt sent to the agent",
      "minLength": 1
    },
    "model": {
      "type": "string",
      "description": "model id (e.g. claude-opus-4-7, gpt-5)",
      "minLength": 1
    },
    "context_refs": {
      "type": "array",
      "description": "list of file paths + line ranges the agent read",
      "minItems": 1
    },
    "verifier": {
      "type": "string",
      "description": "tests/lints/manual-check that confirmed the diff before commit",
      "minLength": 1
    },
    "author": {
      "type": "string",
      "description": "named human who reviewed and committed",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
